INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'How much space is needed?', 'The amount of space needed varies by package. Please see below for dimensions for each package:
Indoor Sleepovers and Lounges
Tent Sleepover- Each A-Frame Tent set up requires approximately a 3ft by 6ft space
Lace Teepee Sleepover- Each Teepee set up requires approximately a 3.5ft by 6.5ft space
Outdoor Sleepovers and Lounges
Standard MEGALounge & MEGA GlampOut- 5M MEGATent- Requires a 25ft by 25ft grass area for staking (actual tent is 17ft diameter)
Deluxe MEGALounge & MEGA GlampOut- 6M MEGATent- Requires a 32ft by 32ft grass area for staking (actual tent is 20ft in diameter)
The MEGATent must be set up on a flat grass surface. Non grass surfaces (pavement, stone, turf, sand, etc.) will require sandbags for an additional fee of $150. This must be disclosed at the time of booking.
Dining
Celebrations Picnics- We recommend a 8ft x 10ft space for a table of 8. Please contact us for exact dimensions for larger parties.
Farm Table Dining- Each Farm Table is 8ft x 3ft.
Dining in the Tent- 5M MEGATent requires a 25ft by 25ft grass area for staking (actual tent is 17ft diameter); 6M MEGATent requires a 32ft by 32ft grass area for staking (actual tent is 20ft in diameter)', 0 FROM packages WHERE slug = 'tent-sleepover';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'What if I don''t have my final guest count yet?', 'We recommend booking for the maximum number of guests that you may have as we can not guarantee that additional items will be available. You have up until 2 weeks before your event (when your final payment is due) to make any changes.', 1 FROM packages WHERE slug = 'tent-sleepover';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'What if I need to cancel?', 'Cancellation 2 Weeks +
If you have to cancel or reschedule your event your 25% deposit may be used as a credit towards a new event within 13 months of your original event date. In addition, you are entitled to a refund of any amount paid above the 25% deposit.
Cancellations within 2 Weeks
If you are canceling your event within 2 weeks, your full payment may be used as a credit towards a new event within 13 months of your original event date.
Cancellations within 24 hours
If you are canceling your event within 24 hours of your scheduled delivery time, your full payment, minus a rescheduling fee, may be used as a credit towards a new event within 13 months of your original event date.', 2 FROM packages WHERE slug = 'tent-sleepover';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'When do you set up and pick up?', 'You will receive a confirmation email one week prior to your event with a 2 hour delivery and pick up window. We base our schedule on your event start/end time provided at time of booking, location, package, etc.
Deliveries: Deliveries will begin at 8:00am for outdoor events and 9:00am for indoor events and go throughout the day. All sleepover packages will be set up by 4:00pm. Some deliveries may take place the day prior to your event depending on the schedule for that particular date.
Pick Ups: All Sleepover Packages- Pick ups will begin at 10:00am the next day and go throughout the day. All MEGATent Packages- Pick ups will begin at 8:00am the next day and go throughout the day. Picnic Packages- pick up scheduling depends on guest counts, package type, location, weather and other scheduled events. Guaranteed specific delivery/pick up times may incur additional fees and must be requested via email no later than 2 weeks before your event.', 3 FROM packages WHERE slug = 'tent-sleepover';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'How is everything cleaned?', 'Every item is thoroughly cleaned and sanitized between events: linens are freshly laundered, mattresses and cushions are wiped down and deodorized, and tents are fully disinfected. Everything arrives fresh and ready for your celebration.', 4 FROM packages WHERE slug = 'tent-sleepover';
