INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'Where can I hold my event?', 'Currently, we are only servicing private residences or venues. We do not serve public parks or beaches at this time.
If you are looking to hold an event at a beach or park please check out our DIY Picnic Package.', 0 FROM packages WHERE slug = 'celebrations-picnic-adult';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'What happens if it rains?', 'We highly suggest you have a backup plan for all outdoor events in case of inclement weather. Back up plans can include: Moving your picnic indoors, Set up your picnic under a covered area (provided by the client) such as a covered porch, canopy, pop-up tent, etc., Upgrade your package to one of our Dining in the Tent options (pending availability). You also do have the option to reschedule for another date pending availability. You must notify us a minimum of 24 hours before your scheduled delivery window in order to reschedule.', 1 FROM packages WHERE slug = 'celebrations-picnic-adult';
