INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'When will I get my damage deposit back?', 'Your damage deposit will be refunded the Monday after your event as long as all inventory is returned free from any damage.
Damage includes but is not limited to any of the following: stains, broken inventory, missing pieces, and water damage (including damage from tents being left open and items being left out in the rain and/or overnight).
Please note damage deposits are only charged for OUTDOOR events.', 4 FROM packages WHERE slug = 'farm-table-dining';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'Can I choose my theme/color scheme?', 'Yes! We have several themes/color schemes for you to choose from. We can also put together a custom theme for your event. Additional fees may apply for custom themes. Price varies based on level of customization and size of event. Please contact us for a quote.', 5 FROM packages WHERE slug = 'farm-table-dining';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'How much space is needed?', 'The amount of space needed varies by package. Please see below for dimensions for each package:
Indoor Sleepovers and Lounges
Tent Sleepover- Each A-Frame Tent set up requires approximately a 3ft by 6ft space
Lace Teepee Sleepover- Each Teepee set up requires approximately a 3.5ft by 6.5ft space
Outdoor Sleepovers and Lounges
Standard MEGALounge & MEGA GlampOut- 5M MEGATent- Requires a 25ft by 25ft grass area for staking (actual tent is 17ft diameter)
Deluxe MEGALounge & MEGA GlampOut- 6M MEGATent- Requires a 32ft by 32ft grass area for staking (actual tent is 20ft in diameter)
The MEGATent must be set up on a flat grass surface. Non grass surfaces (pavement, stone, turf, sand, etc.) will require sandbags for an additional fee of $150. This must be disclosed at the time of booking.
Dining
Celebrations Picnics- We recommend a 8ft x 10ft space for a table of 8. Please contact us for exact dimensions for larger parties.
Farm Table Dining- Each Farm Table is 8ft x 3ft.
Dining in the Tent- 5M MEGATent requires a 25ft by 25ft grass area for staking (actual tent is 17ft diameter); 6M MEGATent requires a 32ft by 32ft grass area for staking (actual tent is 20ft in diameter)', 0 FROM packages WHERE slug = 'megaglampout';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'What happens if it rains?', 'We highly suggest you have a backup plan for all outdoor events in case of inclement weather. Back up plans can include: Moving your picnic indoors, Set up your picnic under a covered area (provided by the client) such as a covered porch, canopy, pop-up tent, etc., Upgrade your package to one of our Dining in the Tent options (pending availability). You also do have the option to reschedule for another date pending availability. You must notify us a minimum of 24 hours before your scheduled delivery window in order to reschedule.', 1 FROM packages WHERE slug = 'megaglampout';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'What if I need to cancel?', 'Cancellation 2 Weeks +
If you have to cancel or reschedule your event your 25% deposit may be used as a credit towards a new event within 13 months of your original event date. In addition, you are entitled to a refund of any amount paid above the 25% deposit.
Cancellations within 2 Weeks
If you are canceling your event within 2 weeks, your full payment may be used as a credit towards a new event within 13 months of your original event date.
Cancellations within 24 hours
If you are canceling your event within 24 hours of your scheduled delivery time, your full payment, minus a rescheduling fee, may be used as a credit towards a new event within 13 months of your original event date.', 2 FROM packages WHERE slug = 'megaglampout';
