INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'Do you need access to power?', 'Yes, access to power is needed to run the projector. We will provide ample extension cords.', 2 FROM packages WHERE slug = 'megamovie-night';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'Do you provide the movie?', 'While we do not provide the movie we will provide either a DVD/Blue Ray Player or FireStick. You are responsible for providing a DVD/Blue Ray or for streaming a movie through your own account (Netflix, Hulu, etc.). Please note that if you plan to stream a movie there must be a strong internet signal (wifi or data) available at the movie site.', 3 FROM packages WHERE slug = 'megamovie-night';
INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'Do you stay for the event?', 'We do not stay for the event. We set up everything you need, leave you to enjoy your event and return the next day (or later that day upon request).', 4 FROM packages WHERE slug = 'megamovie-night';
