INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'What do guests get to keep?', 'Each guest gets to keep their Spa Slippers, Spa Headband, Applicator Brush, and Facial Products (face wipes, face mask, lotion) and Mani/Pedi Products (bath bomb, toe separators, nail file, nail brush). Robes are for event use only, but personalized satin robes can be added as an option for guests to keep.', 1 FROM packages WHERE slug = 'pamper-party';
