INSERT INTO package_faqs (package_id, question, answer, sort_order) SELECT id, 'How is everything cleaned?', 'Every item is thoroughly cleaned and sanitized between events: linens are freshly laundered, mattresses and cushions are wiped down and deodorized, and tents are fully disinfected. Everything arrives fresh and ready for your celebration.', 3 FROM packages WHERE slug = 'pamper-party';
